mapper.select:
select ear.id, ear.user_id, ear.attendance_date, ear.check_in_time, ear.check_out_time, ear.state, ear.department_id, ear.create_time, ear.update_time, COALESCE(e.name, su.name) as userName, sd.name as departmentName from emp_attendance_record ear left join sys_user su on ear.user_id = su.id left join emp e on su.id = e.user_id left join sys_dept sd on ear.department_id = sd.id
and ear.user_id = #{userId}
and (e.name like CONCAT('%', #{empName}, '%') or su.name like CONCAT('%', #{empName}, '%'))
and ear.attendance_date >= #{attendanceDateStart}
and ear.attendance_date <= #{attendanceDateEnd}
and ear.state = #{state}
and ear.department_id = #{departmentId}
order by ear.attendance_date desc, ear.create_time desc

SELECT
id,user_id,attendance_date,check_in_time,check_out_time,state,department_id,create_time,update_time
FROM emp_attendance_record
WHERE user_id = #{userId}
AND attendance_date = #{attendanceDate}
